@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           class="product-search-input" />

    @if (_loading)
    {
        <div class="product-search-status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search-status product-search-error">
            Something went wrong. Please try again.
        </div>
    }
    else if (_results is not null && _results.Count == 0)
    {
        <div class="product-search-status">No products found.</div>
    }

    @if (_results is { Count: > 0 })
    {
        <div class="product-search-results">
            @foreach (var product in _results)
            {
                <div class="product-card" @onclick="() => OnProductSelected.InvokeAsync(product)">
                    <img src="@product.ImageUrl" alt="@product.Name" class="product-card-image" />
                    <div class="product-card-name">@product.Name</div>
                    <div class="product-card-price">@product.Price.ToString("C")</div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product>? _results;
    private bool _loading;
    private Exception? _error;

    private CancellationTokenSource? _debounceTokenSource;
    private CancellationTokenSource? _searchTokenSource;

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        var query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce timer and any in-flight search.
        _debounceTokenSource?.Cancel();
        _debounceTokenSource?.Dispose();
        _debounceTokenSource = new CancellationTokenSource();

        _searchTokenSource?.Cancel();
        _searchTokenSource?.Dispose();
        _searchTokenSource = new CancellationTokenSource();

        var debounceCt = _debounceTokenSource.Token;
        var searchCt = _searchTokenSource.Token;

        if (string.IsNullOrWhiteSpace(query))
        {
            _results = null;
            _error = null;
            _loading = false;
            return;
        }

        try
        {
            await Task.Delay(300, debounceCt);
        }
        catch (TaskCanceledException)
        {
            // User typed again — abandon this search.
            return;
        }

        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            _results = await ProductService.SearchAsync(query, searchCt);
        }
        catch (OperationCanceledException)
        {
            // Superseded by a newer search — don't touch state.
            return;
        }
        catch (Exception ex)
        {
            _results = null;
            _error = ex;
        }
        finally
        {
            // Only clear loading if this search wasn't cancelled.
            if (!searchCt.IsCancellationRequested)
            {
                _loading = false;
            }
        }
    }

    public void Dispose()
    {
        _debounceTokenSource?.Cancel();
        _debounceTokenSource?.Dispose();
        _searchTokenSource?.Cancel();
        _searchTokenSource?.Dispose();
    }
}

